import React from "react";
import Link from "next/link";
export default function Topcategories() {
  const list = [
    { image: "/topcategoriesimages/1.png", name: "HeadPhoes" },
    { image: "/topcategoriesimages/2.png", name: "Moniters"  },
    { image: "/topcategoriesimages/4.png", name:  "PC Gaming" },
    { image: "/topcategoriesimages/3.png", name:  "Laptops" },
  ];
  return (
    <div className="py-10 px-10 bg-white rounded-4xl shadow-xl">
  <h1 className="text-xl mb-10 font-bold text-black">
    Top Categories
  </h1>

  <div className="ps-5 grid grid-cols-4 gap-16">
    {list.map((item, index) => {
      return (
        <div
          key={index}
          className="flex flex-col items-center justify-between h-25 text-center"
        >
            <Link href={"/"} >
            <img
            src={item.image}
            alt="brand"
            className="h-16 object-contain"
          />
            </Link>
          <Link href="/" className="mt-2 font-semibold hover:bg-gray-200 rounded-2xl p-1">{item.name}</Link>
        </div>
      );
    })}
  </div>
</div>
  );
}
